package polytrade

import "testing"

func TestEncodeMultiSendGolden(t *testing.T) {
	txns := []SafeTransaction{
		{
			To:        USDCAddress,
			Value:     "0",
			Data:      "0xa9059cbb000000000000000000000000d8da6bf26964af9d7eed9e03e53415d37aa9604500000000000000000000000000000000000000000000000000000000000f4240",
			Operation: OperationCall,
		},
		{
			To:        CTFExchange,
			Value:     "0",
			Data:      "0x095ea7b3000000000000000000000000e2222d279d744050d28e00520010520000310f59ffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffff",
			Operation: OperationCall,
		},
	}
	got := encodeMultiSend(txns)
	const want = ""
	if got != want {
		t.Errorf("encoded mismatch:\n  got:  %s\n  want: %s", got, want)
	}
}
